steps.value:
let subPrice = "{{subPrice}}"
let unitPrice = "{{unitPrice}}"

subPrice = subPrice.replace(",","");
unitPrice = unitPrice.replace(",","");

subPrice = Number(subPrice.replace("{{Symbol}}",""));
unitPrice = Number(unitPrice.replace("{{Symbol}}",""));

let subtotal = subPrice+unitPrice;
subtotal = "{{Symbol}}"+subtotal.toFixed(2);

return subtotal

let unit = "{{unitPrice}}";
